external_knowledge:
- "Top-tier racers" refers to greyhounds that have placed in the top three positions; 
- "More than a handful of races" denotes more than five races or at least six races; 
- The term "average winnings" implies the average prize money earned by each greyhound.

sql:
SELECT SUM(r.prize) AS total_earnings
FROM results r
WHERE r.race_status = 'finished' AND r.prize > 0;

SELECT COUNT(race_id) AS total_races
FROM races
WHERE race_date = '2023-08-15' AND location = 'Sand Track 1';

SELECT AVG(win_time) AS average_winning_time
FROM results
WHERE position = 1;

SELECT name, age, breed
FROM greyhounds
ORDER BY age DESC;

SELECT location, COUNT(race_id) AS number_of_races, AVG(estimated_time) AS average_estimated_time
FROM races
GROUP BY location;

SELECT AVG(prize) AS average_prize
FROM results
WHERE win_time < (SELECT AVG(win_time) FROM results);

SELECT AVG(win_time) AS average_win_time
FROM results
WHERE win_time < 30;

SELECT AVG(win_time) AS average_win_time
FROM results
WHERE race_id = 123;

SELECT name
FROM greyhounds
WHERE greyhound_id = 0;

SELECT SUM(prize) AS total_prize_money
FROM results
WHERE race_id = 123;

SELECT gender, COUNT(*) AS number_of_greyhounds
FROM greyhounds
GROUP BY gender;
